namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string OfficeLocation { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public int MaxEnrollment { get; set; }
    public int CurrentEnrollment { get; set; }
    public bool IsFeatured { get; set; }
    public int DepartmentId { get; set; }
    public int InstructorId { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = [];

    public CatalogService()
    {
        _departments =
        [
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, patterns, and quantitative reasoning across pure and applied domains." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Analysis of literature, rhetoric, and written communication across historical and contemporary contexts." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces that govern the natural world." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events, societies, and cultures to understand the forces that shaped the modern world." },
            new() { Id = 6, Code = "BIOL", Name = "Biology", Description = "Study of living organisms, their structures, functions, evolution, and interactions with the environment." },
        ];

        _instructors =
        [
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers in top-tier conferences and holds three patents in natural language processing. She received her PhD from MIT and has been teaching at the university for 15 years.", Email = "achen@university.edu", OfficeLocation = "Science Building 301" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Bio = "Dr. Martinez focuses on abstract algebra and number theory. He is the author of two widely adopted textbooks and has mentored numerous graduate students. He joined the department after a postdoctoral fellowship at Princeton.", Email = "rmartinez@university.edu", OfficeLocation = "Math Hall 210" },
            new() { Id = 3, Name = "Prof. Sarah Williams", Title = "Professor", Bio = "Prof. Williams is a literary scholar specializing in 19th-century American literature and critical theory. She has received multiple teaching awards and serves on the editorial board of the American Literary Review.", Email = "swilliams@university.edu", OfficeLocation = "Humanities Building 105" },
            new() { Id = 4, Name = "Dr. James Park", Title = "Assistant Professor", Bio = "Dr. Park researches quantum computing and condensed matter physics. Before joining academia, he spent five years at a national laboratory working on quantum error correction. He is passionate about making physics accessible to all students.", Email = "jpark@university.edu", OfficeLocation = "Physics Lab 415" },
            new() { Id = 5, Name = "Dr. Maria Johnson", Title = "Professor", Bio = "Dr. Johnson is a historian of early modern Europe with a focus on the social history of science. She has authored three books and regularly contributes to public history projects and museum exhibitions.", Email = "mjohnson@university.edu", OfficeLocation = "History Wing 220" },
            new() { Id = 6, Name = "Dr. David Lee", Title = "Associate Professor", Bio = "Dr. Lee studies molecular biology and genetics. His research lab investigates gene regulation mechanisms in cancer cells. He has secured significant grant funding from the NIH and mentors both undergraduate and graduate researchers.", Email = "dlee@university.edu", OfficeLocation = "Life Sciences 312" },
            new() { Id = 7, Name = "Dr. Emily Turner", Title = "Lecturer", Bio = "Dr. Turner specializes in software engineering and web technologies. With a decade of industry experience before joining academia, she brings practical insights to the classroom and leads the university's coding bootcamp program.", Email = "eturner@university.edu", OfficeLocation = "Science Building 205" },
        ];

        _courses =
        [
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to the field of computer science. Topics include problem-solving strategies, basic programming concepts using Python, data representation, and an overview of how computers work. No prior programming experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Building 101", MaxEnrollment = 120, CurrentEnrollment = 98, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Emphasizes efficiency analysis using Big-O notation.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Building 203", MaxEnrollment = 60, CurrentEnrollment = 55, IsFeatured = false, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, CourseCode = "CS 310", Title = "Web Application Development", Description = "Hands-on course covering modern web development with HTML, CSS, JavaScript, and server-side frameworks. Students build full-stack applications and learn about RESTful APIs, databases, and deployment.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Science Building 105", MaxEnrollment = 40, CurrentEnrollment = 38, IsFeatured = true, DepartmentId = 1, InstructorId = 7 },
            new() { Id = 4, CourseCode = "MATH 151", Title = "Calculus I", Description = "First course in single-variable calculus covering limits, continuity, derivatives, and an introduction to integration. Applications to physics, engineering, and the natural sciences are emphasized throughout.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Hall 100", MaxEnrollment = 150, CurrentEnrollment = 130, IsFeatured = true, DepartmentId = 2, InstructorId = 2 },
            new() { Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Introduction to vectors, matrices, determinants, eigenvalues, and linear transformations. Covers both computational techniques and theoretical foundations with applications in data science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Math Hall 205", MaxEnrollment = 80, CurrentEnrollment = 62, IsFeatured = false, DepartmentId = 2, InstructorId = 2 },
            new() { Id = 6, CourseCode = "ENG 110", Title = "Expository Writing", Description = "Develops skills in analytical reading and persuasive writing. Students compose essays in multiple genres, practice revision strategies, and learn to construct clear, evidence-based arguments for academic audiences.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Humanities 202", MaxEnrollment = 25, CurrentEnrollment = 24, IsFeatured = false, DepartmentId = 3, InstructorId = 3 },
            new() { Id = 7, CourseCode = "ENG 225", Title = "American Literature Survey", Description = "Survey of major works and movements in American literature from the colonial period to the present. Readings include works by Hawthorne, Whitman, Dickinson, Fitzgerald, Morrison, and contemporary authors.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Location = "Humanities 105", MaxEnrollment = 35, CurrentEnrollment = 28, IsFeatured = true, DepartmentId = 3, InstructorId = 3 },
            new() { Id = 8, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Introduction to classical mechanics covering kinematics, Newton's laws, work and energy, momentum, rotational motion, and gravitation. Includes a weekly laboratory component with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", Location = "Physics Lab 100", MaxEnrollment = 90, CurrentEnrollment = 75, IsFeatured = false, DepartmentId = 4, InstructorId = 4 },
            new() { Id = 9, CourseCode = "PHYS 305", Title = "Quantum Mechanics", Description = "Introduction to the principles of quantum mechanics including wave-particle duality, the Schrödinger equation, quantum states, operators, and measurement theory. Prerequisites: PHYS 201 and MATH 250.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Physics Lab 310", MaxEnrollment = 30, CurrentEnrollment = 22, IsFeatured = true, DepartmentId = 4, InstructorId = 4 },
            new() { Id = 10, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and transformative events from prehistory through the late medieval period. Covers Mesopotamia, Egypt, Greece, Rome, China, the Islamic world, and sub-Saharan Africa.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", Location = "History Wing 101", MaxEnrollment = 100, CurrentEnrollment = 82, IsFeatured = false, DepartmentId = 5, InstructorId = 5 },
            new() { Id = 11, CourseCode = "HIST 320", Title = "The Scientific Revolution", Description = "Explores the transformation of natural philosophy into modern science during the 16th and 17th centuries. Examines the work of Copernicus, Galileo, Kepler, and Newton within their social and intellectual contexts.", Credits = 3, Schedule = "Thu 6:00–8:50 PM", Location = "History Wing 205", MaxEnrollment = 35, CurrentEnrollment = 18, IsFeatured = false, DepartmentId = 5, InstructorId = 5 },
            new() { Id = 12, CourseCode = "BIOL 110", Title = "Principles of Biology", Description = "Foundational course covering cell biology, genetics, evolution, and ecology. Emphasizes the scientific method and includes a laboratory component where students design and conduct experiments.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM + Wed Lab 1:00–3:50 PM", Location = "Life Sciences 100", MaxEnrollment = 100, CurrentEnrollment = 88, IsFeatured = true, DepartmentId = 6, InstructorId = 6 },
            new() { Id = 13, CourseCode = "BIOL 340", Title = "Molecular Genetics", Description = "Advanced study of gene structure, expression, and regulation at the molecular level. Topics include DNA replication, transcription, translation, recombinant DNA technology, and genomics.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", Location = "Life Sciences 215", MaxEnrollment = 40, CurrentEnrollment = 31, IsFeatured = false, DepartmentId = 6, InstructorId = 6 },
            new() { Id = 14, CourseCode = "CS 450", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search algorithms, knowledge representation, machine learning, neural networks, and natural language processing. Students complete a semester-long project applying AI to a real-world problem.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Location = "Science Building 301", MaxEnrollment = 45, CurrentEnrollment = 42, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
        ];
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.Find(d => d.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.Find(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.Find(i => i.Id == id);

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

