@page "/"
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Explore our departments and courses for the upcoming semester. Find the right classes and submit your enrollment request online.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Description[..Math.Min(120, course.Description.Length)]…</p>
                    <p class="mb-1"><strong>Credits:</strong> @course.Credits | <strong>Schedule:</strong> @course.Schedule</p>
                    <span class="badge bg-secondary">@dept?.Name</span>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                    <a href="enroll?courseId=@course.Id" class="btn btn-outline-success btn-sm">Enroll</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 col-lg-3 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Code</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private IReadOnlyList<Course> featuredCourses = [];
    private IReadOnlyList<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

