else
{
    @if (validationErrors.Count > 0)
    {
        <div class="alert alert-danger">
            <strong>Please correct the following errors:</strong>
            <ul class="mb-0 mt-1">
                @foreach (var error in validationErrors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="row">
        <div class="col-lg-8">
            <div class="card">
                <div class="card-body">
                    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                        <AntiforgeryToken />

                        <div class="mb-3">
                            <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                            <input type="text" class="form-control" id="studentName" name="Model.StudentName" value="@Model.StudentName" />
                        </div>

                        <div class="mb-3">
                            <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                            <input type="text" class="form-control" id="studentId" name="Model.StudentId" value="@Model.StudentId" placeholder="e.g., S12345678" />
                        </div>

                        <div class="mb-3">
                            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                            <select class="form-select" id="courseId" name="Model.CourseId">
                                <option value="0">— Select a course —</option>
                                @foreach (var course in courses)
                                {
                                    if (course.Id == Model.CourseId)
                                    {
                                        <option value="@course.Id" selected>@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                                    }
                                    else
                                    {
                                        <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                                    }
                                }
                            </select>
                        </div>

                        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                    </form>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();

    private IReadOnlyList<Course> courses = [];
    private List<string> validationErrors = [];
    private bool submitted;
    private Course? selectedCourse;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        // Pre-select course from query string on initial GET
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            validationErrors.Add("Full Name is required.");

        if (string.IsNullOrWhiteSpace(Model.StudentId))
            validationErrors.Add("Student ID is required.");

        if (Model.CourseId <= 0)
            validationErrors.Add("Please select a course.");

        if (validationErrors.Count > 0)
            return;

        selectedCourse = Catalog.GetCourse(Model.CourseId);
        Catalog.SubmitEnrollmentRequest(Model);
        submitted = true;
    }
}

