<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Search by title, code, or keyword..." />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select class="form-select" id="departmentId" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                if (dept.Id == DepartmentId)
                {
                    <option value="@dept.Id" selected>@dept.Name</option>
                }
                else
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (selectedDept is not null)
{
    <div class="alert alert-info">
        <strong>@selectedDept.Name (@selectedDept.Code)</strong> — @selectedDept.Description
    </div>
}

<p class="text-muted">Showing @courses.Count course(s)</p>

<div class="table-responsive">
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th>Availability</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = Catalog.GetDepartment(course.DepartmentId);
                var spotsLeft = course.MaxEnrollment - course.CurrentEnrollment;
                <tr>
                    <td><strong>@course.CourseCode</strong></td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td>
                        @if (spotsLeft <= 5)
                        {
                            <span class="badge bg-danger">@spotsLeft spots left</span>
                        }
                        else
                        {
                            <span class="badge bg-success">@spotsLeft spots left</span>
                        }
                    </td>
                    <td>
                        <a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private IReadOnlyList<Department> departments = [];
    private Department? selectedDept;

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.SearchCourses(Search, DepartmentId);
        if (DepartmentId.HasValue)
            selectedDept = Catalog.GetDepartment(DepartmentId.Value);
    }
}

