@page "/"
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Explore our departments and courses for the upcoming semester. Find the right classes and submit your enrollment request online.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Description[..Math.Min(120, course.Description.Length)]…</p>
                    <p class="mb-1"><strong>Credits:</strong> @course.Credits | <strong>Schedule:</strong> @course.Schedule</p>
                    <span class="badge bg-secondary">@dept?.Name</span>
                </div>
                <div class="card-footer">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                    <a href="enroll?courseId=@course.Id" class="btn btn-outline-success btn-sm">Enroll</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 col-lg-3 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Code</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private IReadOnlyList<Course> featuredCourses = [];
    private IReadOnlyList<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

toolArgs.file_text:
@page "/courses/{Id:int}"
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <PageTitle>@course.CourseCode — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="courses?departmentId=@course.DepartmentId">@department?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-lg-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Course Description</h5></div>
                <div class="card-body">
                    <p>@course.Description</p>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Schedule &amp; Location</h5></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Schedule</dt>
                        <dd class="col-sm-9">@course.Schedule</dd>
                        <dt class="col-sm-3">Location</dt>
                        <dd class="col-sm-9">@course.Location</dd>
                        <dt class="col-sm-3">Credits</dt>
                        <dd class="col-sm-9">@course.Credits</dd>
                        <dt class="col-sm-3">Department</dt>
                        <dd class="col-sm-9">@department?.Name (@department?.Code)</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Enrollment</h5></div>
                <div class="card-body">
                    @{
                        var spotsLeft = course.MaxEnrollment - course.CurrentEnrollment;
                    }
                    <p>
                        <strong>@course.CurrentEnrollment</strong> / @course.MaxEnrollment enrolled
                        —
                        @if (spotsLeft <= 5)
                        {
                            <span class="badge bg-danger">@spotsLeft spots remaining</span>
                        }
                        else
                        {
                            <span class="badge bg-success">@spotsLeft spots remaining</span>
                        }
                    </p>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success">Submit Enrollment Request</a>
                </div>
            </div>
        </div>

        <div class="col-lg-4">
            @if (instructor is not null)
            {
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">Instructor</h5></div>
                    <div class="card-body">
                        <h5>@instructor.Name</h5>
                        <p class="text-muted mb-2">@instructor.Title</p>
                        <p>@instructor.Bio</p>
                        <hr />
                        <p class="mb-1"><strong>Email:</strong> @instructor.Email</p>
                        <p class="mb-0"><strong>Office:</strong> @instructor.OfficeLocation</p>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;
    private Instructor? instructor;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
        if (course is not null)
        {
            department = Catalog.GetDepartment(course.DepartmentId);
            instructor = Catalog.GetInstructor(course.InstructorId);
        }
    }
}

@page "/enroll"
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course. You will receive a confirmation from the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request for <strong>@selectedCourse?.CourseCode — @selectedCourse?.Title</strong> has been submitted successfully.</p>
        <hr />
        <p class="mb-0">The registrar's office will review your request and send confirmation to your university email.</p>
    </div>
    <a href="courses" class="btn btn-primary">Browse More Courses</a>
    <a href="enroll" class="btn btn-outline-secondary">Submit Another Request</a>
}
else
{
    @if (validationErrors.Count > 0)
    {
        <div class="alert alert-danger">
            <strong>Please correct the following errors:</strong>
            <ul class="mb-0 mt-1">
                @foreach (var error in validationErrors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="row">
        <div class="col-lg-8">
            <div class="card">
                <div class="card-body">
                    <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                        <AntiforgeryToken />

                        <div class="mb-3">
                            <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                            <input type="text" class="form-control" id="studentName" name="Model.StudentName" value="@Model.StudentName" />
                        </div>

                        <div class="mb-3">
                            <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                            <input type="text" class="form-control" id="studentId" name="Model.StudentId" value="@Model.StudentId" placeholder="e.g., S12345678" />
                        </div>

                        <div class="mb-3">
                            <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                            <select class="form-select" id="courseId" name="Model.CourseId">
                                <option value="0">— Select a course —</option>
                                @foreach (var course in courses)
                                {
                                    if (course.Id == Model.CourseId)
                                    {
                                        <option value="@course.Id" selected>@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                                    }
                                    else
                                    {
                                        <option value="@course.Id">@course.CourseCode — @course.Title (@course.Credits cr.)</option>
                                    }
                                }
                            </select>
                        </div>

                        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                    </form>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();

    private IReadOnlyList<Course> courses = [];
    private List<string> validationErrors = [];
    private bool submitted;
    private Course? selectedCourse;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();

        // Pre-select course from query string on initial GET
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        validationErrors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            validationErrors.Add("Full Name is required.");

        if (string.IsNullOrWhiteSpace(Model.StudentId))
            validationErrors.Add("Student ID is required.");

        if (Model.CourseId <= 0)
            validationErrors.Add("Please select a course.");

        if (validationErrors.Count > 0)
            return;

        selectedCourse = Catalog.GetCourse(Model.CourseId);
        Catalog.SubmitEnrollmentRequest(Model);
        submitted = true;
    }
}

